import React from 'react';
import { Box, Typography, Slider } from '@mui/material';

const ColorPicker = ({ color, onColorChange, lineWidth, onLineWidthChange }) => {
  const presetColors = [
    '#000000', // Black
    '#FF0000', // Red
    '#00FF00', // Green
    '#0000FF', // Blue
    '#FFFF00', // Yellow
    '#FF00FF', // Magenta
    '#00FFFF', // Cyan
    '#FFA500', // Orange
    '#800080', // Purple
    '#008000', // Dark Green
    '#800000', // Maroon
    '#000080', // Navy
  ];

  return (
    <Box sx={{ p: 2, backgroundColor: '#f8f9fa', borderRadius: 2, mb: 2 }}>
      <Typography variant="subtitle1" sx={{ 
        fontWeight: 600, 
        mb: 2,
        fontFamily: "'Poppins', sans-serif",
        color: '#2d3748'
      }}>
        Color Settings
      </Typography>
      
      <Box sx={{ mb: 3 }}>
        <Typography variant="body2" sx={{ 
          mb: 1,
          fontFamily: "'Inter', sans-serif",
          color: '#4a5568'
        }}>
          Preset Colors
        </Typography>
        <Box sx={{ 
          display: 'grid', 
          gridTemplateColumns: 'repeat(6, 1fr)', 
          gap: 1,
          mb: 2
        }}>
          {presetColors.map((presetColor) => (
            <Box
              key={presetColor}
              onClick={() => onColorChange(presetColor)}
              sx={{
                width: 32,
                height: 32,
                backgroundColor: presetColor,
                borderRadius: '50%',
                cursor: 'pointer',
                border: color === presetColor ? '3px solid #4a5568' : '2px solid #e2e8f0',
                transition: 'transform 0.2s',
                '&:hover': {
                  transform: 'scale(1.1)',
                },
              }}
            />
          ))}
        </Box>
      </Box>

      <Box sx={{ mb: 2 }}>
        <Typography variant="body2" sx={{ 
          mb: 1,
          fontFamily: "'Inter', sans-serif",
          color: '#4a5568'
        }}>
          Custom Color
        </Typography>
        <input
          type="color"
          value={color}
          onChange={(e) => onColorChange(e.target.value)}
          style={{
            width: '100%',
            height: '40px',
            padding: '2px',
            border: '2px solid #e2e8f0',
            borderRadius: '8px',
            cursor: 'pointer',
          }}
        />
      </Box>

      <Box>
        <Typography variant="body2" sx={{ 
          mb: 1,
          fontFamily: "'Inter', sans-serif",
          color: '#4a5568'
        }}>
          Line Width: {lineWidth}px
        </Typography>
        <Slider
          value={lineWidth}
          onChange={(_, value) => onLineWidthChange(value)}
          min={1}
          max={20}
          step={1}
          marks
          sx={{
            color: color,
            '& .MuiSlider-thumb': {
              width: 20,
              height: 20,
            },
            '& .MuiSlider-track': {
              height: 6,
            },
            '& .MuiSlider-rail': {
              height: 6,
            },
          }}
        />
      </Box>
    </Box>
  );
};

export default ColorPicker;
